  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"from-incheon-seoul-day-tour-cruise-guests","locale":"en","product_id":"from-incheon-seoul-day-tour-cruise-guests","seo":{"pageTitle":"From Incheon: Seoul Cruise Day Tour (Small Group) | AtoC Korea","metaDescription":"9-hour shared-van shore excursion from Incheon Cruise Terminal to Seoul: Gyeongbokgung Palace, Bukchon Hanok Village, Gwangjang Market, Insadong. EN guide.","primaryKeywords":["Incheon cruise day tour","Seoul shore excursion small group","From Incheon Seoul day tour","Gyeongbokgung cruise tour"],"ogImage":"https://images.unsplash.com/photo-1538485399081-7191377e8241?w=1200"},"catalog_card":{"thumbnail":"https://images.unsplash.com/photo-1538485399081-7191377e8241?w=800","title":"From Incheon: Seoul Day Tour for Cruise Guests (Small Group)","priceLabel":"Price TBD — confirm small-group rate from GetYourGuide listing","shortCardDescription":"Shared-van day tour from Incheon Cruise Terminal hitting Seoul''s headline central-city stops in a single 9-hour window: Gyeongbokgung Palace (or Changdeokgung on Tuesdays), Bukchon Hanok Village, lunch at Gwangjang Market (the city''s most-photographed streetfood alley), and Insadong cultural street. Pickup calibrated to your specific ship''s disembarkation; certified English/Chinese-speaking guide; ≈75 min return drive built in.","tags":["small_group","seoul","cruise_excursion","from_cruise","shared_van"],"rating":0,"reviewCount":0,"slug":"from-incheon-seoul-day-tour-cruise-guests","subtitle":"Seoul''s central heritage, hanok, market, and crafts circuit from your Incheon cruise terminal.","region":"Seoul (from Incheon cruise terminal)","duration":"9 hours","stopsCount":6,"badges":["Cruise excursion","Small shared van","Pickup at Incheon port","9-hour window"],"heroImage":"https://images.unsplash.com/photo-1538485399081-7191377e8241?w=800"},"headlineLine1":"Cruise port to royal palace, hanok lanes to streetfood —","headlineLine2":"Seoul''s central headline circuit in a single shared-van day","price":{"amountLabel":"","currency":"USD","per":"person","priceSource":"getyourguide_t1051171","priceNote":"Cruise excursion price not yet confirmed from operator listing. Comparable Seoul-from-Incheon shared cruise tours range $90–$120 per person. Once confirmed, AtoC Korea sale price applies a flat 10% discount.","discountPercent":10},"hero":{"imageUrl":"https://images.unsplash.com/photo-1538485399081-7191377e8241?w=1600","imagePosition":"center 35%","tagline":"Four central-Seoul stops coordinated with your ship''s schedule","pills":["small_group","cruise","seoul"],"meta":{"duration":"≈ 9 hours, calibrated to your cruise''s port-call window","region":"Seoul (from Incheon cruise terminal)","stops":"7 stops","rating":0,"ratingStars":0}},"subnavItems":[{"id":"overview","label":"Overview"},{"id":"itinerary","label":"Itinerary"},{"id":"details","label":"Details"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"Reviews"}],"glanceItems":[{"icon":"clock","label":"Duration","value":"≈ 9 hours, ship-to-ship (calibrated to your cruise schedule)"},{"icon":"users","label":"Group","value":"Small group, shared van with other cruise passengers (typically up to ≈10)"},{"icon":"ship","label":"Pickup","value":"Incheon Port International Passenger Terminal (Songdo) — arrival hall"},{"icon":"footprints","label":"Walking","value":"Moderate — ≈4 km. Palace courtyards, Bukchon lanes, Gwangjang market alleys, Insadong street."},{"icon":"ticket","label":"Includes","value":"Vehicle, certified guide. Excludes: Gyeongbokgung admission (₩3,000, free with hanbok), lunch (≈₩10,000–₩20,000), tips."},{"icon":"map-pin","label":"Region","value":"Seoul (from Incheon cruise terminal)"}],"galleryItems":[{"id":"g1","type":"photo","src":"https://images.unsplash.com/photo-1538485399081-7191377e8241?w=1200","alt":"Gyeongbokgung''s Geunjeongjeon throne hall with mountain backdrop","caption":"Gyeongbokgung — the throne hall Geunjeongjeon, National Treasure No. 223. Built 1395, rebuilt 1867.","location":"Gyeongbokgung Palace, Seoul","atmosphere":"Wide stone courtyard, painted eaves, mountain backdrop"},{"id":"g2","type":"photo","src":"https://images.unsplash.com/photo-1535139262971-c51845709a48?w=1200","alt":"Tile-roofed hanok houses along a sloping lane in Bukchon","caption":"Bukchon Hanok Village — ≈600 traditional houses in a designated conservation area since 1976.","location":"Bukchon Hanok Village, Seoul","atmosphere":"Quiet hanok lanes, residential, soft slopes"},{"id":"g3","type":"photo","src":"https://images.unsplash.com/photo-1502175353174-a7a44e84da10?w=1200","alt":"Vendors and customers crowded around a streetfood stall at Gwangjang Market","caption":"Gwangjang Market — Korea''s first permanent indoor market (1905). Bindae-tteok and mayak gimbap are the signatures.","location":"Gwangjang Market, Jongno-gu","atmosphere":"Communal counters, sizzling stalls, market chatter"},{"id":"g4","type":"photo","src":"https://images.unsplash.com/photo-1605640840605-14ac1855827b?w=1200","alt":"Pedestrianized street with traditional craft shops and signage in Insadong","caption":"Insadong — Seoul''s traditional craft and antiques street; designated a Cultural Street in 1988.","location":"Insadong, Jongno-gu","atmosphere":"Pedestrian-only, calligraphy and craft signage, tea-house alleys"},{"id":"g5","type":"photo","src":"https://images.unsplash.com/photo-1601471569526-2c7d5e1b7e5f?w=1200","alt":"Cruise ship docked at Incheon Port''s international passenger terminal","caption":"Incheon Cruise Terminal in Songdo — pickup and drop-off point.","location":"Incheon Port International Passenger Terminal","atmosphere":"Working port, cruise-passenger flow"}],"itineraryStops":[{"number":1,"time":"≈ 09:00","duration":"30 min","name":"Incheon Cruise Terminal pickup","category":"Departure","description":"Pickup at Incheon Cruise Terminal — Korea''s flagship cruise facility, opened April 25, 2019 in Songdo International Business District as a USD 580 million investment capable of berthing the world''s largest cruise ships including Royal Caribbean''s Oasis-Class (228,000 tons / 6,370 passengers). After clearing immigration (budget ~30 min), look for the small-group van at the curbside meeting point with your name placard. Drive time to central Seoul is approximately 60-90 minutes via the Yeongjong Bridge and the Incheon-Seoul Expressway, with views of the Yellow Sea industrial coastline transitioning to the high-rise Han River corridor. The 2026 season runs a record 75+ cruise calls, and the terminal sits 7 km from the nearest Incheon Subway Line 1 station — not walkable — making the pre-arranged tour van the most efficient port-to-Seoul option. Beyond the cruise terminal itself, the Songdo International Business District (opened 2003 as Korea''s first Free Economic Zone) is a fully-planned ''smart city'' with **Songdo Central Park** (a saltwater canal park 5 minutes by taxi) as the main short-stay attraction for guests with <8-hour shore time. **Free port shuttle** to Incheon Subway Line 1 ''International Business District Station'' is offered on most cruise calls (verify in terminal lobby on arrival). **As of January 1, 2026**, South Korea requires a **mandatory digital e-Arrival Card** for visitors without K-ETA exemption — completing K-ETA registration before sailing (USD 8, 3-year validity) eliminates the form-fill step at the gangway.","highlights":["Curbside pickup at Incheon Cruise Terminal (opened Apr 2019, capacity for Oasis-Class ships)","60-90 min drive to central Seoul via Yeongjong Bridge + Incheon-Seoul Expressway","Driver-guide with English-language commentary en route","Designed for cruise passengers: built around your ship''s all-aboard time","**South Korea''s largest cruise terminal** — 2-story 7,364 m² building (1F arrivals / 2F departures); USD 580M total project investment; opened **April 25, 2019**","**Berths Royal Caribbean Oasis-Class** ships (228,000 GT, 6,370 passengers + 2,400 crew) — also handles MSC Bellissima, Diamond Princess, Spectrum of the Seas (2026/27 season)","**Free port shuttle** from terminal to Incheon Subway Line 1 ''International Business District Station'' (cruise-line dependent — verify in terminal lobby on arrival)","**200-vehicle parking lot** including 156 large-bus capacity for tour-operator pickups","**Mandatory digital e-Arrival Card since January 1, 2026** for visitors without K-ETA exemption — recommend K-ETA registration before sailing (USD 8, 3-year validity)"],"timeUsed":["Disembark cruise ship and clear Korean immigration (~30 min)","Meet driver-guide at curbside pickup point","Begin 60-90 min drive to first Seoul stop","Pre-departure check: K-ETA / e-Arrival Card status verification (~5 min)","Free port shuttle option check at terminal lobby (~5 min if applicable)"],"whyOnRoute":"Incheon Cruise Terminal pickup is the day''s logistical anchor — without a pre-arranged transfer, cruise passengers face a 7-km gap from terminal to nearest metro station and a 60-90 min taxi to Seoul. The shared-van format keeps cost competitive while preserving the directness of door-to-door service. For cruise guests this pickup is the day''s hard-cost-deciding stop — pre-arranged transfers eliminate the 7-km port-to-metro gap and the 60-90-min taxi alternative. Sharing the van with up to 7 other passengers keeps cost competitive (~30-50% of private-charter price) while preserving door-to-door directness; the all-aboard time is built into the day''s schedule with a 90-minute reboarding buffer.","visitBasics":{},"convenience":{},"smartNotes":{"tip":"Allow 30 min minimum for Korean immigration. Keep passport + cruise card accessible. The terminal address in Korean is 인천항 크루즈터미널 (연수구 국제항만대로 438) — DO NOT confuse with the older Incheon International Ferry Terminal."},"_poi_meta":{"poi_key":"incheon_cruise_terminal","verified":true,"match":"operational_pickup","kb_version":"1.26","verified_date":"2026-04-29","note":"Operational pickup stop; references KB POI for terminal facts but kept brief as transit","sources":["Incheon Port Authority (incheonport.kr)","Korea Tourism Organization (VisitKorea — Incheon Cruise Terminal listing)","Korea Herald (April 26, 2019 opening coverage)","Visit Korea — Incheon Tourist Attraction official","Wikipedia (Incheon Port + Songdo International Business District)"]}},{"number":2,"time":"≈ 10:30","duration":"90 min","name":"Gyeongbokgung Palace","category":"Royal Palace","description":"Gyeongbokgung — meaning ''Palace Greatly Blessed by Heaven'' — was the main royal palace of the Joseon Dynasty, built 1395 (3rd year of King Taejo''s reign) as the heart of the new capital Hanyang (now Seoul). It is the largest of the Five Grand Palaces of Joseon and once contained 330+ buildings serviced by 3,000 staff. Burned during the 1592 Imjin War, the palace lay in ruins for 273 years until King Gojong rebuilt it in 1867; the Japanese colonial administration demolished much of the rebuilt complex 1910-1945, and the painstaking restoration that began in 1990 continues today. Three centerpieces define the visit: **Geunjeongjeon Throne Hall** — the largest wooden building in Korea, where kings held court and received foreign envoys; **Gyeonghoeru Pavilion** — a two-story pavilion on 48 stone pillars over a lotus pond, used for royal banquets; and **Hyangwonjeong Pavilion** — a hexagonal pavilion on a small island reached by a covered bridge, considered Korea''s most photographed garden scene. The **Royal Guard Changing Ceremony** takes place daily at 10:00 and 14:00 (approximately 20 min) — guards in vivid blue, red, and yellow Joseon-era uniforms with traditional drums and horns recreate the historic palace gate-protection ritual. **Critical scheduling note**: Gyeongbokgung is CLOSED ON TUESDAYS — when this falls, the tour substitutes Changdeokgung Palace, the only Korean palace inscribed as UNESCO World Heritage (1997), which is closed Mondays instead. Visitors wearing hanbok (traditional Korean dress, rentable nearby in Bukchon for ~15,000 KRW/4hr) enter the palace FREE — a popular photo-trip combination.","highlights":["Joseon Dynasty''s main royal palace — built 1395 as the heart of new Seoul","Geunjeongjeon Throne Hall — largest wooden building in Korea","Gyeonghoeru Pavilion (48-pillar pavilion on lotus pond, royal banquets)","Royal Guard Changing Ceremony at 10:00 + 14:00 (~20 min, daily except Tuesdays)","Hyangwonjeong Pavilion — Korea''s most photographed garden scene","FREE admission for visitors wearing hanbok","**Closed Tuesdays** — Changdeokgung (UNESCO World Heritage 1997) is the substitute","**Royal Guard Changing Ceremony re-enacted since 1996** based on Cultural Heritage Administration historical research — went on hiatus after 2008 Sungnyemun arson incident, resumed 2016 (with the 70+ performer authentic-armor format used today)","**3 additional ceremonies between main 10:00 + 14:00 changes**: Gwanghwamun Gate Guard Ceremony at 11:00 + 13:00; Public Training of Royal Guard Soldiers at 09:35 + 13:35 — total 6 daily reenactments (except Tuesdays)"],"timeUsed":["Arrival, ticketing, and orientation by driver-guide (~10 min)","Royal Guard Changing Ceremony viewing if timing permits (~20 min at 10:00 or 14:00)","Self-paced walk through main throne halls + Gyeonghoeru + Hyangwonjeong (~50 min)","Photo time + reassembly at vehicle (~10 min)","Optional National Folk Museum or National Palace Museum extension (within grounds, free) (~15 min)"],"whyOnRoute":"Gyeongbokgung is Seoul''s #1 must-see and the natural opener for any first-day-in-Seoul itinerary. Picked over Deoksugung (the smaller Western-influenced palace) because the changing-of-the-guard pageantry, the scale of the throne-hall complex, and the photogenic Gyeonghoeru/Hyangwonjeong pavilions deliver a single 90-min visit that explains 500 years of Joseon court life in concrete visual terms — essential for cruise passengers with one day in Korea. For cruise guests, the 90-min Gyeongbokgung dwell is also the day''s primary deep-history anchor — first-time Korea visitors leave with a concrete visual framework (palace scale + ceremony pageantry + photogenic pavilions) that contextualizes every other Joseon-era reference in the country.","visitBasics":{"hours":"Mar-May, Sep-Oct: 09:00-18:00; Jun-Aug: 09:00-18:30; Nov-Feb: 09:00-17:00 (last admission 1 hr before close)","closed":"**Tuesdays** (substitute Changdeokgung when needed)","admission":"Adult 3,000 KRW / Child 1,500 KRW; FREE for hanbok-wearers; Royal Palace Pass 10,000 KRW (4 palaces + Jongmyo, 3 months)","walking":"Moderate — flat extensive grounds; ~1.5-2 km of walking through the main complex"},"convenience":{"restroom":"At main entrance, mid-grounds, and rear pavilion area","parking":"Limited; tour bus drop-off zones at Gwanghwamun"},"smartNotes":{"photo":"Gwanghwamun gate at sunrise / golden hour. Royal Guard Changing Ceremony 10:00 + 14:00. Gyeonghoeru Pavilion reflected in lotus pond. Hyangwonjeong''s covered bridge in spring (cherry blossoms) or autumn (foliage). Hanbok-wearers in front of throne-hall stairs.","facilities":"National Folk Museum of Korea + National Palace Museum of Korea both INSIDE Gyeongbokgung grounds (separate free admission). Cafes, restrooms, gift shop near entrance.","tip":"Time the visit for the 10:00 Changing of the Guard — arrive 09:50 at Heungnyemun Gate. Skip Tuesday — closed (Changdeokgung substitute). Hanbok rental in Bukchon (5 min walk) is 15,000-20,000 KRW for 4 hours and saves the 3,000 KRW admission. Combine with Bukchon Hanok Village naturally — both within 10-min walk."},"_poi_meta":{"poi_key":"gyeongbokgung_palace","verified":true,"match":"single_poi","kb_version":"1.26","verified_date":"2026-04-29","sources":["Cultural Heritage Administration of Korea (Royal Palaces & Tombs Center)","Visit Seoul official (english.visitseoul.net)","Korea Tourism Organization (VisitKorea)","Korea.net (official ROK government portal)","Wikipedia (Gyeongbokgung Palace)"]}},{"number":3,"time":"≈ 12:15","duration":"75 min","name":"Bukchon Hanok Village","category":"Hanok Residential District","description":"Bukchon literally means ''Northern Village'' — a 600-year-old hanok (traditional Korean tile-roofed house) residential district nestled between Gyeongbokgung Palace and Changdeokgung Palace, originally home to high-ranking Joseon Dynasty government officials and aristocracy. Today Bukchon is Seoul''s largest concentration of preserved hanok homes — approximately 900 traditional houses arrayed along eight famous viewpoints (Bukchon 8 Gyeong / Bukchon 8 Views) — with sloping alleys giving views of N Seoul Tower in the distance and the curved tile-roof rooflines layering down toward the city below. The signature view is Gye-dong-gil (Hanok Roofline Alley near Bukchon No. 6 viewpoint) where photographers gather for the iconic shot of cascading hanok rooftops with N Seoul Tower in the distance. Many hanok along the route are private residences (residents have asked tourists to stay quiet — signs request silence after 22:00 and limited photography of doorways). Cultural workshops scattered through the village offer hands-on experiences in Korean knot-tying, hanji (mulberry paper) crafts, traditional tea ceremonies, embroidery, and Korean cooking. Hanbok rental shops cluster at the village edge (~15,000-20,000 KRW for 4 hours) — the standard photo-trip pairing with Gyeongbokgung. Insadong, the cultural and crafts shopping street, sits a 5-10 minute walk south. The village''s preservation is overseen by **Jongno-gu District Office''s Bukchon Hanok Village preservation program** — strict zoning rules limit commercial signage, renovation must use traditional materials (handmade hanji paper screens, wooden frames, tile roofs), and resident-quiet hours 22:00–10:00 are enforced by signage and community wardens during peak season.","highlights":["Seoul''s largest preserved hanok district — ~900 traditional homes in a single compact area","Bukchon 8 Gyeong (8 famous viewpoints) — the iconic hanok-roofline-with-N-Seoul-Tower view at #6","Live residential village (not a museum) — residents request quiet hours and respectful behavior","Cultural workshops: Korean knot-tying, hanji paper crafts, tea ceremony, embroidery","Hanbok rental shops at village edge for free Gyeongbokgung admission combo","5-10 min walk to Insadong cultural street","**~600 years old** — historic district between Gyeongbokgung and Changdeokgung Palaces, originally home to Joseon Dynasty high-ranking officials and aristocracy","**Resident-quiet hours 22:00–10:00 enforced** — village is a LIVING residential community (not a museum); cultural respect protocol critical (no flash photography in alleys, voices down, no drones)","**Combination Royal Palaces Ticket ₩10,000 adult / ₩5,000 child** covers all 4 royal palaces (Gyeongbokgung + Changdeokgung incl. Secret Garden + Changgyeonggung + Deoksugung) + Jongmyo Shrine — 3-month validity; savings vs single tickets if pairing with private hanok-tour day"],"timeUsed":["Brief orientation by driver-guide (~5 min)","Self-paced walk along the Bukchon 8 viewpoints (~50-60 min)","Optional cultural workshop OR teahouse stop OR hanbok photo session (~15 min)","Reassembly at meeting point","Optional hanbok rental + photo session at village edge (15,000-20,000 KRW / 4 hr) (~15 min if pre-booked)"],"whyOnRoute":"Bukchon is the natural pivot from Gyeongbokgung''s grand-scale royal architecture to a domestic-scale Joseon-era streetscape — completing the ''how kings AND aristocrats lived 500 years ago'' narrative within walking distance. Picked over Namsangol Hanok Village (a curated open-air museum) because Bukchon is a LIVING village with residents — far more authentic for the story-driven cruise passenger window. For cruise guests on a one-day-in-Seoul window, Bukchon delivers the day''s strongest ''period-set'' photo opportunity — hanok rooflines + Insadong-bound alley vistas + the Bukchon 8 Gyeong viewpoints make this a 75-min Instagram-grade stop within walking distance of both Gyeongbokgung and Insadong.","visitBasics":{"hours":"24 hours (lanes always accessible); residents request quiet 22:00-10:00","closed":"Open year-round; some private hanok museums may close on Mondays","admission":"Free entry to lanes (workshops + private museums charge 5,000-10,000 KRW)","walking":"Moderate — cobbled, sloped alleys; comfortable shoes essential"},"convenience":{"restroom":"Tourist Information Center at Bukchon entrance; cafes scattered through the village","parking":"Limited; walking-distance from Gyeongbokgung"},"smartNotes":{"photo":"**Bukchon 8 Gyeong (8 Famous Views)** — the #6 viewpoint at Gye-dong-gil for the iconic hanok-roofline-and-N-Seoul-Tower shot. Hanbok-wearers framed against tile-roof gables. Ssamzigil cultural alley (covered alley with shops at the south edge near Insadong).","facilities":"Tourist Information Center near Anguk Station Exit 2 with multilingual maps. Coffee shops, traditional teahouses, hanok-converted cafes scattered through the village. Photo zones marked.","tip":"**Visit before noon or after 16:00** — residents have publicly requested quieter visits; some lanes have signs prohibiting tour groups during early-morning resident hours. Stay quiet and on the marked photo paths. Hanbok rental shops at the village edge — Hanboknam, Oneday Hanbok, etc. Combine with Insadong (5 min walk) and Gyeongbokgung (10 min walk) for a Seoul-northside half-day."},"_poi_meta":{"poi_key":"bukchon_hanok_village","verified":true,"match":"single_poi","kb_version":"1.26","verified_date":"2026-04-29","sources":["Visit Seoul official (english.visitseoul.net)","Bukchon Traditional Culture Center","Jongno-gu District Office (Bukchon Hanok Village preservation program)","Korea Tourism Organization (VisitKorea)","Wikipedia (Bukchon Hanok Village)"]}},{"number":4,"time":"≈ 13:45","duration":"75 min","name":"Lunch at Gwangjang Market","category":"Market & Streetfood Lunch","description":"Gwangjang Market — opened 1905 as Korea''s first permanent traditional market — sits in Jongno-gu about 10 minutes east of Bukchon and is the city''s most-photographed streetfood alley, made world-famous by Anthony Bourdain''s ''Parts Unknown'' Seoul episode and again by Netflix''s ''Street Food: Asia.'' The covered alley layout puts dozens of cheek-by-jowl vendors specializing in Seoul''s signature snacks: **bindaetteok** (mung-bean pancakes ground fresh on stone mills, fried golden-crisp in pork-lard pans — the market''s most iconic dish, 5,000-7,000 KRW per pancake); **mayak gimbap** (literally ''drug gimbap'' — bite-sized seaweed-rice rolls dipped in mustard-soy sauce, named for their addictive quality, 3,000-5,000 KRW per plate); **yukhoe** (Korean-style raw beef tartare with pear and egg yolk — Cham Sundae stall #18 is the famous purveyor); **sundae** (Korean blood sausage); **tteokbokki** (spicy rice cakes); **kalguksu** (handmade knife-cut noodle soup); **soondae-guk** and **gopchang-jeongol** (offal stew). Beyond the food alley: the market''s cloth-and-textile district on the second floor (silks, Korean wedding hanbok fabrics) is a separate Korea-only specialty. Cruise passengers typically eat at sit-down counters where each vendor has 5-10 stools — pay-as-you-order, mostly cash, English menu boards now available at most stalls. Critical: most vendors are CASH-ONLY. Bring 10,000-20,000 KRW per person. Note: peak lunch crowds 12:00-14:00 mean wait times — the 13:45 arrival is timed for the easing-off post-peak hour.","highlights":["Opened 1905 — Korea''s FIRST permanent traditional market","World-famous after Anthony Bourdain''s ''Parts Unknown'' + Netflix ''Street Food: Asia''","Bindaetteok (mung-bean pancake — the market''s iconic dish, fried in pork lard)","Mayak gimbap (''drug gimbap'' — bite-sized addictive seaweed-rice rolls)","Yukhoe (Korean-style raw beef tartare) at Cham Sundae stall #18","Cash-only at most stalls — bring 10,000-20,000 KRW per person","Second-floor textile/hanbok-fabric district","**Anthony Bourdain''s ''Parts Unknown'' Seoul episode (CNN, June 21, 2015)** + **Netflix ''Street Food: Asia'' (2019)** = catapulted Gwangjang to international food-pilgrimage status; pre-Bourdain it was a working-class market unknown to international tourists","**General market 09:00–18:00** (textile + hanbok-fabric + traditional dry goods upper level) **/ Food alley 09:00–23:00** (most stalls 11:00 onward) — Sundays + holidays see lighter crowds for early-bird visits"],"timeUsed":["Orientation walk-through by driver-guide (~10 min)","Lunch at recommended stall(s) (~30-40 min)","Free time for additional snacks or souvenir shopping (~20 min)","Reassembly at vehicle","Second-floor textile / hanbok-fabric district browse (~10 min if interested)"],"whyOnRoute":"Gwangjang is Seoul''s most authentic non-tourist food experience — a working-class market that international media made world-famous without it losing its character. Picked over Namdaemun Market (larger but more Chinese-tour-bus dominated) because Gwangjang''s food alley is a single covered ribbon perfect for a 75-min lunch stop — the alley''s compact layout means cruise passengers see a dozen specialties in a single pass, eat at one or two counters, and leave full. For cruise guests, the 75-min Gwangjang lunch slot is the day''s most cost-efficient meal — bindaetteok + mayak gimbap + tteokbokki for ~10,000-15,000 KRW per person vs ~25,000-40,000 KRW for a comparable Insadong sit-down lunch.","visitBasics":{"hours":"Most stalls 09:00-23:00 daily; food alley peaks 11:00-21:00","closed":"Open year-round; some textile-floor stalls closed Sundays","admission":"Free entry; pay-as-you-go (cash-only at most food stalls)","walking":"Easy — flat covered alley; comfortable shoes for narrow stall-stool access"},"convenience":{"restroom":"Inside the market building (signposted)","parking":"Limited; nearest paid parking ~5 min walk"},"smartNotes":{"photo":"Bindaetteok being fried on the stone mills (pork-lard pans) — the iconic shot. Mayak gimbap rolling counters. Yukhoe plates at Cham Sundae #18. Hanging dried fish/seaweed displays. The covered-alley overhead view.","facilities":"Many vendors have small sit-down dining areas behind their stalls. Multilingual menu boards. Some now accept cards but assume cash-only. ATMs near Jongno 5-ga Station Exit 7.","tip":"**Bring CASH 10,000-20,000 KRW per person.** Try bindaetteok + mayak gimbap as the must-eat pair. Avoid seasoning samples without intent to purchase (Korean market etiquette). Visit before 12:00 OR after 14:00 to skip peak crowds. Yukhoe (raw beef) is safe — vendors source same-day fresh — but skip if you''re sensitive to raw foods. Pair the food alley with the second-floor textile district if you want a Korean wedding hanbok souvenir."},"_poi_meta":{"poi_key":"gwangjang_market","verified":true,"match":"single_poi","kb_version":"1.26","verified_date":"2026-04-29","sources":["Gwangjang Market Association (jangjeonjang.com)","Visit Seoul official","Korea Tourism Organization (VisitKorea)","Anthony Bourdain: Parts Unknown — Seoul (CNN, June 21, 2015)","Wikipedia (Gwangjang Market)"]}},{"number":5,"time":"≈ 15:15","duration":"75 min","name":"Insadong cultural street","category":"Crafts & Cultural Shopping Street","description":"Insadong (인사동) is Seoul''s premier traditional crafts and cultural street — a pedestrian-friendly main road plus a network of side alleys lined with antique shops, calligraphy supplies, hanji (mulberry paper) workshops, ceramic galleries, traditional teahouses, and Korean souvenir vendors. Originally settled in the late Joseon era as a residential district for retired aristocrats and government officials, Insadong became a center for traditional Korean cultural commerce in the 20th century and remains the city''s go-to district for hanbok accessories, traditional tea sets, and museum-quality calligraphy supplies. The signature landmark is **Ssamzigil** — a 4-story spiral cultural complex at the heart of Insadong with 70+ small craft shops, art galleries, cafes, and a rooftop terrace; designed in 2004 around a continuous spiral ramp that takes shoppers from ground to roof in a single seamless walk. Other Insadong specialties: **traditional teahouses** (jeontongchatjip — try Mokyeon for omija five-flavor tea or Suyeonsanbang for the classical experience); **hanji paper workshops** (handmade Korean mulberry paper folding/stamping demos); **ceramic galleries** showing Goryeo celadon and Joseon white porcelain; and **Balwoo Gongyang** — Korea''s only Michelin-starred Buddhist temple-cuisine restaurant, run by the Jogye Order (next to Jogyesa Temple, 5 min walk). The street is cleared of vehicles for pedestrian-only access on weekends (Sat-Sun). Insadong''s main pedestrian street stretches **~700 meters** from Anguk Station to Jongno-3-ga, with branch alleys hosting the densest concentration of traditional-craft vendors in central Seoul.","highlights":["Seoul''s premier traditional crafts and cultural shopping street","Ssamzigil — 4-story spiral cultural complex with 70+ shops, galleries, cafes","Traditional teahouses (jeontongchatjip): Mokyeon, Suyeonsanbang for classical tea ceremony","Hanji (mulberry paper) workshops with hands-on folding/stamping demos","Ceramic galleries: Goryeo celadon and Joseon white porcelain","Balwoo Gongyang — Korea''s only Michelin-starred Buddhist temple cuisine restaurant nearby","Pedestrian-only on weekends (Saturday + Sunday)","**Pedestrian-only on Saturdays + Sundays** (vehicles cleared) — best photo days; weekday vehicle-share zone has narrower walking margins","**Jogyesa Temple 5-min walk south** — head temple of Jogye Order (Korea''s largest Buddhist denomination); FREE admission, the only major traditional temple in central Seoul; Daeungjeon = largest temple building in Seoul; 500-year-old Baeksong (Natural Monument No. 9)"],"timeUsed":["Orientation walk-through by driver-guide (~10 min)","Free time for shopping and gallery browsing (~50 min)","Optional traditional teahouse or hanji workshop (~15 min)","Reassembly at vehicle","Optional Jogyesa Temple side-trip (5-min walk south, FREE) (~15 min)"],"whyOnRoute":"Insadong closes the Seoul highlights loop with the city''s strongest traditional-crafts shopping experience — the natural complement to Bukchon''s residential hanok and Gwangjang''s working-class food culture. Picked over the Dongdaemun area (larger but fashion-and-modern-shopping focused) because Insadong''s craft-and-tea concentration is unmatched in Seoul and aligns with the cruise-passenger souvenir-purchase window. For cruise guests, Insadong is the day''s primary souvenir-purchase window — Korean ceramics + hanji paper + tea + traditional crafts are concentrated in this single 700-m pedestrian street, eliminating the need for fragmented shopping across multiple Seoul districts.","visitBasics":{"hours":"Most shops 10:00-22:00; teahouses typically 11:00-22:00","closed":"Open year-round; individual galleries may close Mondays","admission":"Free entry; pay-as-you-go for purchases and teahouses","walking":"Easy — flat pedestrian street; cobblestone alleys at edges"},"convenience":{"restroom":"Ssamzigil + Tourist Information Center at Anguk Station Exit 6","parking":"Limited; walking from Bukchon (5 min) or Jongno 3-ga subway access"},"smartNotes":{"photo":"Ssamzigil spiral interior + rooftop terrace. Traditional teahouse interiors with hanji-paper screens. Hanji workshops mid-demo. Korean wedding-color thread bundles at hanbok-accessory shops. Pedestrian-only weekend street view.","facilities":"Cafes, teahouses, restaurants, galleries throughout. Tourist Information Center at Anguk Station Exit 6. Tax refund counters at major souvenir shops. ATMs at Anguk Station and Jongno 3-ga Station.","tip":"**Best souvenirs**: hanji paper crafts, traditional ink stamps (dojang), small ceramics, Korean knot-tying kits, traditional tea sampler boxes. Skip if you don''t shop — the street''s appeal is browse-and-buy. Ssamzigil rooftop terrace has photo-worthy city views and is free entry. Balwoo Gongyang Michelin temple cuisine requires advance reservation. Visit on Saturday or Sunday when the street is fully pedestrian (no cars)."},"_poi_meta":{"poi_key":"insadong","verified":true,"match":"single_poi","kb_version":"1.26","verified_date":"2026-04-29","sources":["Visit Seoul official","Insa-dong Tourism Information Center","Korea Tourism Organization (VisitKorea)","Jongno-gu District Office","Wikipedia (Insadong)"]}},{"number":6,"time":"≈ 16:45","duration":"75 min","name":"Return drive to Incheon Cruise Terminal","category":"Return","description":"Return drive 60-90 minutes from central Seoul back to the Incheon Cruise Terminal at Songdo, arriving with a 60-90 min buffer before typical 19:00-20:00 all-aboard times. Route runs via the Incheon-Seoul Expressway and Yeongjong Bridge in reverse, with traffic conditions typically lighter than the morning commute. Drop-off direct at the terminal curbside — followed by Korean immigration re-entry to the cruise ship (usually fast at this time of day). Confirm your ship''s specific all-aboard time at the terminal before disembarking the van — traffic delays are rare on this expressway but the 90-min cushion is the prudent buffer.","highlights":["60-90 min drive back to Incheon Cruise Terminal","Curbside drop-off at terminal entrance","Designed to arrive 60-90 min before standard all-aboard times"],"timeUsed":["Boarding van at final Seoul stop","60-90 min drive via Incheon-Seoul Expressway","Curbside drop-off at terminal — proceed to ship re-entry"],"whyOnRoute":"Return logistics — the 90-min cushion before ship all-aboard absorbs unexpected traffic and ensures cruise passengers will not be left behind. Independent travelers without this buffer face genuine risk of missing departure (the ship will not wait).","visitBasics":{},"convenience":{},"smartNotes":{"tip":"Cruise terminal Korean address: 인천항 크루즈터미널 (연수구 국제항만대로 438) — keep handy in case driver-confusion (some drivers mistake Cruise Terminal for the older Ferry Terminal). All-aboard time is on your cruise card; confirm before boarding the van."},"_poi_meta":{"poi_key":"OPS_return_incheon","verified":false,"match":"operational_implicit","note":"Operational return stop"}}],"routeFlowStops":[{"name":"Incheon Cruise Terminal","type":"origin","theme":"Departure"},{"name":"Gyeongbokgung Palace (or Changdeokgung on Tuesdays)","type":"primary","theme":"Royal palace"},{"name":"Bukchon Hanok Village","type":"primary","theme":"Hanok residential district"},{"name":"Lunch at Gwangjang Market","type":"meal","theme":"Streetfood market"},{"name":"Insadong cultural street","type":"primary","theme":"Crafts & cultural shopping"},{"name":"Incheon Cruise Terminal","type":"return","theme":"Return"}],"routePhases":[{"phase":"Outbound transfer","duration":"≈ 1.5 hours","description":"Cruise terminal pickup and 60–75 min drive to central Seoul (Gyeongbokgung area)."},{"phase":"Palace + hanok","duration":"≈ 3 hours","description":"Gyeongbokgung Palace (90 min) then Bukchon Hanok Village (75 min) — adjacent stops, 5-min walk between them."},{"phase":"Lunch + crafts street","duration":"≈ 2.5 hours","description":"Streetfood lunch at Gwangjang Market (75 min) then Insadong cultural street (75 min)."},{"phase":"Return drive","duration":"≈ 1.25–1.5 hours","description":"Central Seoul to Incheon Cruise Terminal via Incheon Expressway, with a 60-min buffer before all-aboard."}],"routeShapeIntro":{"title":"How this day flows","subtitle":"A point-to-point shared coach loop that begins and ends at the Incheon Cruise Terminal. The Seoul portion is a walkable cluster — Gyeongbokgung, Bukchon, and Gwangjang Market are within 10 minutes of each other by coach. The shared format keeps the price down compared to a private cruise excursion, while still bundling the transport, guide, and admissions into a single product timed to your ship''s port call."},"whyTourWorks":{"bestFor":["Cruise passengers calling at Incheon with a 9+ hour port window","First-time visitors to Seoul wanting palace + hanok + market + crafts in one day","Couples and adult families","Travelers prioritizing heritage + food in central Seoul"],"lessIdealFor":["Cruise passengers with shorter port-call windows (<8 hours)","Travelers wanting deep palace exploration (90 min covers highlights only)","Travelers who need a tight return buffer (>2 hours) for ship boarding"],"routeLogicSections":[{"title":"Why this route is built this way","icon":"route","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"Adjacent stops in central Seoul, no wasted transit","detail":"Gyeongbokgung, Bukchon, Gwangjang, and Insadong are within a 2 km radius of each other in central Seoul, allowing 5–10 minute drives between stops and even some walking. The only long transit is the 60–75 min outbound and 75 min return between the cruise terminal and central Seoul."},{"label":"Lunch at Gwangjang, not at a separate restaurant","detail":"Streetfood at Gwangjang Market is the day''s main meal. This consolidates lunch + the market experience into one 75-minute stop, keeping the day to 9 hours and giving cruise visitors a more memorable food experience than a generic restaurant lunch."},{"label":"Honest about the Tuesday closure","detail":"Gyeongbokgung is closed on Tuesdays. Most cruise tours don''t disclose this and silently substitute the day''s anchor stop. We tell you upfront: on Tuesdays the tour swaps to Changdeokgung Palace + Secret Garden, which is UNESCO-listed (the Secret Garden adds ₩5,000)."},{"label":"Hanbok hack disclosed","detail":"Wearing a complete hanbok grants free entry to all four major royal palaces in Seoul. Hanbok rental shops are concentrated near the palace district (around Gyeongbokgung''s Gwanghwamun gate and Anguk Station, not inside Bukchon as some guides suggest). Standard 4-hour rental ₩15,000–₩25,000. If you arrive in hanbok you save ₩3,000 admission and the palace photographs are noticeably better — but this requires a 30-min rental detour at the start, which is not built into the route by default."}]}]},"practicalAccordionItems":[{"id":"inclusions","title":"What''s included","preview":"Air-conditioned shared van, certified English/Chinese-speaking guide, fuel/tolls/parking.","content":["Air-conditioned shared van, certified English/Chinese-speaking guide, fuel/tolls/parking.","Not included: Gyeongbokgung admission (₩3,000 adult, FREE with hanbok), Changdeokgung Secret Garden (₩5,000, only applicable on Tuesday substitution), lunch at Gwangjang Market (₩10,000–₩20,000), optional Hanbok rental (₩15,000–₩25,000 for 4-hour rental, available at shops near the palace district — see FAQ), tips.","Total typical out-of-pocket without hanbok: ₩15,000–₩25,000 per person."]},{"id":"pickup","title":"Pickup & drop-off","preview":"Group meets at the Incheon Port International Passenger Terminal arrival hall in Songdo.","content":["Group meets at the Incheon Port International Passenger Terminal arrival hall in Songdo.","Pickup time is calibrated to your ship''s actual disembarkation, not a fixed start.","Provide ship name, port-call date, expected disembarkation time, and all-aboard time at booking.","Drop-off at the terminal with at least a 60-minute buffer before your stated all-aboard time."]},{"id":"sailaway","title":"Sail-away timing","preview":"Drop-off at the cruise terminal at least 60 minutes before your all-aboard time.","content":["Drop-off at the cruise terminal at least 60 minutes before your all-aboard time.","Cruise rule of thumb: be back on the ship at least 30 minutes before stated departure.","The route is built with a 60-minute buffer for return-drive traffic.","Incheon-bound rush hour (≈17:00–19:00) and rain can extend the return drive — the operator monitors and may shorten the Insadong block by 15–30 min if traffic warrants."]},{"id":"walking","title":"Walking & terrain","preview":"Moderate.","content":["Moderate.","Total walking ≈4 km.","Gyeongbokgung covers a large flat-courtyard area; Bukchon has gentle slopes on hanok-lined streets; Gwangjang Market is flat indoor alleys; Insadong is a flat pedestrian street.","No significant stairs except optional Bukchon viewpoints.","Comfortable closed-toe shoes recommended."]},{"id":"cancellation","title":"Cancellation","preview":"Free cancellation up to 24 hours before pickup.","content":["Free cancellation up to 24 hours before pickup.","Same-day cancellations and no-shows non-refundable.","If your ship''s port call is cancelled by the cruise line, full refund with cancellation documentation."]},{"id":"accessibility","title":"Children & accessibility","preview":"Children age 8 and up are welcome and the route works well for them.","content":["Children age 8 and up are welcome and the route works well for them.","Strollers are fine at Gyeongbokgung (flat courtyards) and Insadong, but Bukchon''s hanok lanes have gentle slopes that may be effortful.","Wheelchair users: Gyeongbokgung is wheelchair-friendly via the Heungnyemun gate; the Bukchon viewpoints are not.","Advise mobility needs at booking."]},{"id":"tuesday-route","title":"Tuesday route note","preview":"Gyeongbokgung is closed on Tuesdays.","content":["Gyeongbokgung is closed on Tuesdays.","On Tuesday cruise calls the route swaps to Changdeokgung Palace + Secret Garden, which is a UNESCO World Heritage site (the Secret Garden requires a separate ₩5,000 ticket and is visited on a guided schedule).","The rest of the day stays identical."]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"See seasonal notes"},"tomorrow":{"temp":"—","label":"See seasonal notes"},"_seasonalSummary":"Seoul has four distinct seasons: cold winters (-10 to 5 °C lows), hot humid summers (25–32 °C with monsoon rain in July), and pleasant spring/autumn. The cruise season concentrates April–October."},"seasonalVariations":[{"season":"Spring (Mar–May)","description":"Cherry blossoms at Gyeongbokgung''s pond around the Gyeonghoeru pavilion in early-to-mid April. Cruise arrivals peak in this season."},{"season":"Summer (Jun–Aug)","description":"Long daylight; humid. July monsoon possible — the Gwangjang indoor market becomes the rainy-day option. Carry water."},{"season":"Autumn (Sep–Nov)","description":"Best season for palace photography — clear blue skies, foliage in late October. Comfortable walking weather."},{"season":"Winter (Dec–Feb)","description":"Cold but quiet; Gyeongbokgung courtyards are uniquely peaceful in snow. Bring warm layers — palace courtyards offer no wind shelter."}],"bookingTrustItems":[{"icon":"check-circle","title":"Licensed local operator","description":"Authorized Korean tour operator with full insurance","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"Route specialists","description":"Hand-tuned itinerary, not a generic loop","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"Curated group size","description":"Right-sized for the route","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"Immediately","title":"Instant Confirmation","detail":"Booking confirmation with itinerary summary"},{"timing":"12 hours before","title":"12-Hour Reminder","detail":"Weather update and any route adjustments"},{"timing":"Evening before","title":"Final Pickup Info","detail":"Exact pickup time and driver contact"},{"timing":"Morning of tour","title":"Day-of Route Notes","detail":"Morning briefing based on live conditions"},{"timing":"During tour","title":"Stop-by-Stop Tips","detail":"Real-time guidance at each location"},{"timing":"After tour","title":"Post-tour Support","detail":"Follow-up and recommendations"}],"staticQuestions":[{"id":"q-tuesday","question":"What if my port call falls on a Tuesday?","answer":"Gyeongbokgung is closed Tuesdays. On Tuesday the tour swaps to Changdeokgung Palace + Secret Garden, which is a UNESCO World Heritage site (the only Joseon palace with that designation). The Secret Garden requires a separate ₩5,000 ticket and is visited on a guided-walk schedule (timed entries every 30–60 min). The rest of the day stays identical (Bukchon, Gwangjang, Insadong)."},{"id":"q-hanbok","question":"Where do we rent hanbok?","answer":"Most hanbok rental shops are concentrated near Gyeongbokgung''s Gwanghwamun gate and around Anguk Station — the palace district, not inside Bukchon as some guides suggest. Standard 4-hour rental is ₩15,000–₩25,000 (longer rentals available); rental shops typically include hairstyling. The hanbok hack: complete-hanbok wearers get FREE entry to all four major royal palaces, so wearing one saves the ₩3,000 admission. Rental requires a ≈30 min detour at the start of the day, which is not built into the standard route — advise the guide at booking if you want it added."},{"id":"q-cruise-customize","question":"Can I customize the itinerary for my cruise schedule?","answer":"Limited — this is a fixed-route shared product. Pickup and drop-off times adjust automatically to your specific ship''s disembarkation and all-aboard. The guide can rebalance time within the route (longer at Bukchon, shorter at Insadong, etc.) but cannot swap or drop the four core stops. For full customization (different neighborhoods like Gangnam, Yongsan, or Hongdae, or DMZ excursions), book a private cruise excursion."},{"id":"q-cruise-port-buffer","question":"How early do you return to the cruise terminal?","answer":"Drop-off at least 60 minutes before your all-aboard time. The 75-min return drive is the longest single transit of the day; rush hour and rain can push it to 90 min, which is why the buffer is built in. The guide tracks every passenger''s individual ship schedule and prioritizes return order if multiple ships sail at different times."},{"id":"q-changing-of-the-guard","question":"Will we see the Royal Guard Changing Ceremony?","answer":"Maybe — depends on your ship''s arrival time. The ceremony runs at 10:00 and 14:00 at Gyeongbokgung''s Gwanghwamun gate (except Tuesdays and weather-permitting). With a 09:00 disembarkation example, we typically arrive at the palace around 10:30, which means the 10:00 ceremony has already started or finished. Earlier disembarkations (08:30 or earlier) align better. The guide will time arrival to catch the ceremony if your ship''s schedule allows."},{"id":"q-gwangjang-must-eat","question":"What should I eat at Gwangjang Market?","answer":"Three signatures: bindae-tteok (mung-bean pancakes, the most famous Gwangjang dish and what the market is known for internationally — ≈₩5,000 per pancake, very filling); mayak gimbap (small bite-sized seaweed rice rolls in mustard-vinegar sauce, ≈₩3,000–₩4,000 per bundle, kid-friendly); and yukhoe (raw beef tartare in sesame oil, ≈₩15,000–₩20,000 — Gwangjang''s yukhoe alley has multiple shops, the guide will recommend one). For non-adventurous eaters: kalguksu (knife-cut noodles, ≈₩7,000) or kimbap-and-tteokbokki sets are reliable."},{"id":"q-bukchon-residents","question":"Is Bukchon a tourist village or a residential area?","answer":"Residential. Most of the ≈600 hanoks in Bukchon are private homes; only some are tea houses, craft workshops, or small museums. Quiet hours are observed 22:00–10:00, but the city asks visitors to keep voices down at all hours. Don''t enter private courtyards or photograph people without consent. The eight officially designated ''Bukchon Hanok 8 Views'' are the photo-OK spots."},{"id":"q-vegetarian","question":"Are there vegetarian options at Gwangjang?","answer":"Yes. Bindae-tteok (mung-bean pancakes) is naturally vegetarian; bibim-guksu (cold noodles in spicy sauce, no meat) is reliable; tteokbokki (rice cakes in spicy sauce) is vegetarian if you specify no fish cake. Halal and gluten-free options are limited but possible — please advise at booking so the guide can pre-route."},{"id":"first-time","question":"Is this a good choice for first-time visitors to Seoul?","answer":"Yes — for cruise passengers specifically. The four central stops (palace, hanok, market, crafts) are the most-asked-for in Seoul, and the route is built around the cruise schedule. First-time visitors with one cruise port-call day are the primary audience."},{"id":"walking","question":"How much walking is there?","answer":"≈4 km total. Gyeongbokgung''s flat courtyards are the longest single walk; Bukchon has gentle slopes; Gwangjang and Insadong are flat. Comfortable closed-toe shoes are recommended."},{"id":"family","question":"Is this suitable for families with children?","answer":"Yes for school-age children (≈8+). Kids tend to like the Royal Guard ceremony if timed and the streetfood at Gwangjang. Bukchon''s quiet residential character doesn''t always engage younger kids. Strollers are fine at the palace and Insadong."},{"id":"seniors","question":"Can older adults join comfortably?","answer":"Yes. Pace is moderate; the longest single walk is Gyeongbokgung''s courtyards (flat, with seating). Bukchon''s slopes can be effortful but most viewpoints are reachable on the gentler path. Travelers with significant mobility limitations should consider a private cruise excursion."},{"id":"children","question":"What''s the recommended minimum age?","answer":"Best fit is around age 8 and up — children comfortable with the walking note above and a full-day cruise-paced rhythm. If you bring younger children, please advise at booking so the guide can plan around the limit."},{"id":"rain","question":"What if it rains heavily during the day?","answer":"Light rain: tour runs as planned — most stops have indoor or covered options (palace galleries, market, Insadong arcades). Heavy rain: outdoor palace and Bukchon time may shorten in favor of more market and Insadong time. Typhoon-level: rebooking or full refund."}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.","price":{"amountLabel":"","currency":"USD","per":"person","priceSource":"getyourguide_t1051171","priceNote":"Cruise excursion price not yet confirmed from operator listing. Comparable Seoul-from-Incheon shared cruise tours range $90–$120 per person. Once confirmed, AtoC Korea sale price applies a flat 10% discount.","discountPercent":10}},"pickup_dropoff":{"type":"cruise_terminal_pickup","meeting_points":[{"name":"Incheon Port International Passenger Terminal — arrival hall (Songdo)","time":"Calibrated to ship disembarkation"}],"dropoff_points":[{"name":"Incheon Port International Passenger Terminal","approx_time":"Minimum 60 minutes before all-aboard"}],"hotel_pickup_available":false,"notes":"Provide ship name, port-call date, expected disembarkation time, and all-aboard time at booking. Shared van with other cruise passengers from various ships. The guide tracks each passenger''s individual ship schedule; if multiple ships sail at different times, earliest-sailing passengers are dropped first."},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"from-incheon-seoul-day-tour-cruise-guests","product_type":"small_group","route_type":"fixed_route","destination_region":"korea_mainland","region_type":"seoul_with_incheon_origin","vehicle_type":"minicoach","duration_hours":9,"region_tags":["seoul_jongno","seoul_central"],"theme_tags":["cruise_excursion","palace","culture","first_time_friendly"],"poi_tags":["bukchon_hanok_village","gwangjang_market","gyeongbokgung_palace","insadong"],"pace_level":0.8,"walking_level":0.75,"scenic_level":0.7,"photo_level":1,"culture_level":1,"relax_level":0.6,"first_ti